export type HeroRole = 'Tank' | 'Fighter' | 'Assassin' | 'Mage' | 'Marksman' | 'Support';
export type Tier = 'S' | 'A' | 'B' | 'C' | 'D';
export type Lane = 'EXP' | 'Gold' | 'Mid' | 'Roam' | 'Jungle';
export type SynergyType = 'Engage' | 'Burst' | 'Sustain' | 'Pick' | 'Zone';
export type Playstyle = 'Aggressive' | 'Teamfight' | 'Poke' | 'Split Push' | 'Wombo Combo' | 'Protect the Carry';
export type SkinRarity = 'Normal' | 'Elite' | 'Special' | 'Epic' | 'Legend' | 'Collector';

export interface Hero {
  id: string; name: string; role: HeroRole; lane: Lane; difficulty: number;
  tier: Tier; lore: string; description: string;
  stats: { hp: number; attack: number; defense: number; speed: number };
  skills: { name: string; description: string; type: string }[];
  releaseYear: number; imageColor: string;
}

export interface Faction {
  id: string; name: string; description: string; heroes: string[];
  color: string; bannerTagline: string;
}

export interface Item {
  id: string; name: string; category: 'Attack' | 'Defense' | 'Magic' | 'Movement' | 'Jungle' | 'Roaming';
  price: number; stats: string; description: string; iconColor: string;
}

export interface EmblemBuild {
  role: HeroRole; emblemName: string;
  talents: { tier: number; name: string; description: string }[];
  description: string;
}

export interface BattleSpell {
  id: string; name: string; description: string; bestRoles: HeroRole[];
  cooldown: number; iconColor: string;
}

export interface HeroCombo {
  id: string; hero1: string; hero2: string; comboName: string;
  description: string; synergyType: SynergyType; rating: number;
}

export interface TeamComp {
  id: string; name: string; heroes: string[]; description: string;
  playstyle: Playstyle; difficulty: number;
}

export interface GameMode {
  id: string; name: string; description: string;
  playerCount: number; isCompetitive: boolean; iconColor: string;
}

export interface Tournament {
  id: string; name: string; year: number; winner: string;
  runnerUp: string; prizePool: string; location: string; teams: number;
}

export interface Article {
  id: string; title: string; excerpt: string;
  category: 'Lore' | 'Guide' | 'Esports' | 'Patch' | 'Meta' | 'Tips';
  date: string; readTime: number; content: string; author: string; tags: string[];
}

export interface Skin {
  id: string; hero: string; skinName: string; rarity: SkinRarity;
  theme: string; price: string; color: string; releaseYear: number;
}

export interface QuizQuestion {
  id: string; question: string;
  options: { text: string; roleMapping: HeroRole }[];
  correctRole: HeroRole;
}

